local function solveSyntaxByAddDoEnd(uri, err, results)
    results[#results+1] = {
        title = lang.script.ACTION_ADD_DO_END,
        kind = 'quickfix',
        edit = {
            changes = {
                [uri] = {
                    {
                        start   = err.start,
                        finish  = err.start,
                        newText = 'do ',
                    },
                    {
                        start   = err.finish,
                        finish  = err.finish,
                        newText = ' end',
                    },
                }
            }
        }
    }
end

filters = function ()
    local filters = {}
    for i, scp in ipairs(workspace.folders) do
        local path = furi.decode(scp.uri):gsub('\\', '/')
        filters[i] = {
            pattern = {
                glob = path .. '/**',
                options = {
                    ignoreCase = true,
                }
            },
        }
    end
    return filters
end

